1850→    public synchronized ClientInstanceIds clientInstanceIds(final Duration timeout) {
1851→        if (timeout.isNegative()) {
1852→            throw new IllegalArgumentException("The timeout cannot be negative.");
1853→        }
1854→        if (state().hasNotStarted()) {
1855→            throw new IllegalStateException("KafkaStreams has not been started, you can retry after calling start().");
1856→        }
1857→        if (state().isShuttingDown() || state.hasCompletedShutdown()) {
1858→            throw new IllegalStateException("KafkaStreams has been stopped (" + state + ").");
1859→        }
1860→
1861→        final Timer remainingTime = time.timer(timeout.toMillis());
1862→        final ClientInstanceIdsImpl clientInstanceIds = new ClientInstanceIdsImpl();
1863→
1864→        // (1) fan-out calls to threads
1865→
1866→        // StreamThread for main/restore consumers and producer(s)
1867→        final Map<String, KafkaFuture<Uuid>> clientFutures = new HashMap<>();
1868→        synchronized (changeThreadCount) {
