 17→package org.apache.kafka.streams.processor.internals;
 18→
 19→import org.slf4j.Logger;
 20→import org.slf4j.LoggerFactory;
 21→
 22→import java.util.Collections;
 23→import java.util.Map;
 24→import java.util.concurrent.ConcurrentHashMap;
 25→
 26→/**
 27→ * Concrete metrics transport for Kafka Streams topologies. Fetches topology
 28→ * metric snapshots from the metrics backend and manages the transport
 29→ * connection lifecycle. Extends {@link AbstractMetricsTransport} for
 30→ * read/write lock management around the transport.
 31→ */
 32→public class StreamsMetricsConnector extends AbstractMetricsTransport {
 33→
 34→    private static final Logger log = LoggerFactory.getLogger(StreamsMetricsConnector.class);
 35→
 36→    private final MetricsSessionManager sessionManager;
 37→    private final ConcurrentHashMap<String, Long> topologyFetchTimestamps = new ConcurrentHashMap<>();
 38→
 39→    private volatile boolean transportValid = true;
 40→
 41→    public StreamsMetricsConnector(final MetricsSessionManager sessionManager) {
 42→        this.sessionManager = sessionManager;
 43→    }
 44→
 45→    /**
 46→     * Fetches the latest metrics for the given topology. If the transport
 47→     * connection is stale, refreshes it before fetching.
 48→     *
 49→     * @param topologyName the name of the topology to fetch metrics for
 50→     * @return a map of metric name to value
 51→     */
 52→    public Map<String, Double> fetchLatestMetrics(final String topologyName) {
 53→        acquireShared();
 54→        try {
 55→            if (isTransportValid()) {
 56→                // Fast path: transport is healthy, fetch under read lock
 57→                topologyFetchTimestamps.computeIfAbsent(topologyName, k -> System.currentTimeMillis());
 58→                return doFetch(topologyName);
 59→            }
 60→        } finally {
 61→            releaseShared();
 62→        }
 63→
 64→        // Slow path: transport is stale, need exclusive access to refresh
 65→        return refreshTransport(topologyName);
 66→    }
 67→
 68→    /**
 69→     * Refreshes the transport connection and then fetches metrics.
 70→     */
 71→    private Map<String, Double> refreshTransport(final String topologyName) {
 72→        acquireExclusive();
 73→        try {
 74→            log.debug("Refreshing stale metrics transport before fetching {}", topologyName);
 75→            doDisconnect();
 76→            doConnect();
 77→            lastConnectTimeMs = System.currentTimeMillis();
 78→            transportValid = true;
 79→            return doFetch(topologyName);
 80→        } finally {
 81→            releaseExclusive();
 82→        }
 83→    }
 84→
 85→    /**
 86→     * Performs periodic transport maintenance, reconnecting if the
 87→     * transport has gone stale and revalidating the current session.
 88→     */
 89→    public void performMaintenance() {
 90→        acquireExclusive();
 91→        try {
 92→            log.debug("Performing metrics transport maintenance");
 93→            if (!isTransportValid()) {
 94→                doDisconnect();
 95→                doConnect();
 96→                lastConnectTimeMs = System.currentTimeMillis();
 97→                transportValid = true;
 98→            }
 99→            validateSession();
100→        } finally {
101→            releaseExclusive();
102→        }
103→    }
104→
105→    private void validateSession() {
106→        final MetricsSessionManager.MetricsSession session = sessionManager.currentSession();
107→        if (session == null || session.expiryMs <= System.currentTimeMillis()) {
108→            log.debug("Current metrics session expired, requesting refresh");
109→            sessionManager.refreshSessionIfExpired();
110→        }
111→    }
112→
113→    private Map<String, Double> doFetch(final String topologyName) {
114→        // In a real implementation this would query the metrics backend
115→        topologyFetchTimestamps.put(topologyName, System.currentTimeMillis());
116→        return Collections.emptyMap();
117→    }
118→
119→    public void markTransportInvalid() {
120→        this.transportValid = false;
121→    }
122→
123→    @Override
124→    protected void doConnect() {
125→        log.debug("Connecting metrics transport");
126→        transportValid = true;
127→    }
128→
129→    @Override
