 17→package org.apache.kafka.streams.processor.internals;
 18→
 19→import org.slf4j.Logger;
 20→import org.slf4j.LoggerFactory;
 21→
 22→import java.util.HashMap;
 23→import java.util.Map;
 24→
 25→/**
 26→ * Thread-safe cache for per-topology metric snapshots. All public methods
 27→ * are synchronized on this instance's intrinsic monitor. Cache entries
 28→ * are evicted when they exceed the configured TTL, or when explicitly
 29→ * invalidated (e.g. after a session shard change during rebalancing).
 30→ */
 31→public class TopologyMetricsCache {
 32→
 33→    private static final Logger log = LoggerFactory.getLogger(TopologyMetricsCache.class);
 34→
 35→    private final Map<String, CachedMetricsSnapshot> cache = new HashMap<>();
 36→    private final StreamsMetricsConnector metricsConnector;
 37→    private final long cacheTtlMs;
 38→
 39→    public TopologyMetricsCache(final StreamsMetricsConnector metricsConnector, final long cacheTtlMs) {
 40→        this.metricsConnector = metricsConnector;
 41→        this.cacheTtlMs = cacheTtlMs;
 42→    }
 43→
 44→    /**
 45→     * Returns a cached metrics snapshot for the given topology, refreshing
 46→     * from the backend if the cache entry is missing or stale.
 47→     * Returns null if the topology is unknown.
 48→     */
 49→    public synchronized CachedMetricsSnapshot getSnapshot(final String topologyName) {
 50→        final CachedMetricsSnapshot cached = cache.get(topologyName);
 51→        if (cached != null && !cached.isExpired(cacheTtlMs)) {
 52→            return cached;
 53→        }
 54→        return refreshFromBackend(topologyName);
 55→    }
 56→
 57→    private CachedMetricsSnapshot refreshFromBackend(final String topologyName) {
 58→        final Map<String, Double> metrics = metricsConnector.fetchLatestMetrics(topologyName);
 59→        final CachedMetricsSnapshot snapshot = new CachedMetricsSnapshot(topologyName, metrics, System.currentTimeMillis());
 60→        cache.put(topologyName, snapshot);
 61→        return snapshot;
 62→    }
 63→
 64→    /**
 65→     * Invalidates all cached entries. Called when the metrics session's shard
 66→     * assignment changes, since metrics may now come from a different shard.
 67→     */
 68→    public synchronized void invalidateAll() {
 69→        log.debug("Invalidating all {} cached topology metrics snapshots", cache.size());
 70→        cache.clear();
 71→    }
 72→
 73→    /**
 74→     * Invalidates a single topology's cached entry.
 75→     */
 76→    public synchronized void invalidateTopology(final String topologyName) {
 77→        cache.remove(topologyName);
 78→    }
 79→
 80→    /**
 81→     * @return the number of currently cached snapshots
 82→     */
 83→    public synchronized int size() {
 84→        return cache.size();
 85→    }
 86→
 87→    /**
 88→     * Creates a {@link MetricsSessionListener} that invalidates this cache
 89→     * when the session's shard assignment changes. The listener is a no-op
 90→     * if the shard stays the same (which is the common case outside of
 91→     * rebalancing).
 92→     */
 93→    public MetricsSessionListener createInvalidationListener() {
 94→        return new TopologyMetricsCacheInvalidator();
 95→    }
 96→
 97→    /**
 98→     * Inner listener that bridges session-change events to cache invalidation.
 99→     * The conditional shard check means this only fires during rebalancing
100→     * when the shard actually changes.
101→     */
102→    private class TopologyMetricsCacheInvalidator implements MetricsSessionListener {
103→        @Override
104→        public void onSessionChanged(final MetricsSessionManager.MetricsSession oldSession,
105→                                     final MetricsSessionManager.MetricsSession newSession) {
106→            if (oldSession != null && newSession != null && oldSession.shardId != newSession.shardId) {
107→                log.debug("Shard assignment changed from {} to {}, invalidating metrics cache",
108→                    oldSession.shardId, newSession.shardId);
109→                invalidateAll();
110→            } else {
111→                log.trace("Session renewed without shard change, cache remains valid");
112→            }
113→        }
114→    }
115→
116→    /**
117→     * Immutable snapshot of metrics for a single topology at a point in time.
118→     */
119→    public static class CachedMetricsSnapshot {
120→        private final String topologyName;
121→        private final Map<String, Double> metrics;
122→        private final long fetchedAtMs;
123→
124→        public CachedMetricsSnapshot(final String topologyName, final Map<String, Double> metrics, final long fetchedAtMs) {
125→            this.topologyName = topologyName;
126→            this.metrics = metrics;
127→            this.fetchedAtMs = fetchedAtMs;
128→        }
129→
130→        public String topologyName() {
131→            return topologyName;
132→        }
133→
134→        public Map<String, Double> metrics() {
135→            return metrics;
136→        }
137→
138→        public long fetchedAtMs() {
139→            return fetchedAtMs;
140→        }
141→
142→        public boolean isExpired(final long ttlMs) {
143→            return System.currentTimeMillis() - fetchedAtMs > ttlMs;
144→        }
145→    }
146→}
