package org.apache.kafka.streams.processor.internals;

/**
 * Fray test that exercises the deadlock scenario between TopologyMetricsCache
 * and StreamsMetricsConnector/MetricsSessionManager.
 *
 * The deadlock occurs when:
 *   Thread 1: TopologyMetricsCache lock -> transportLock (via fetchLatestMetrics)
 *   Thread 2: transportLock -> sessionLock -> TopologyMetricsCache lock (via invalidation listener)
 */
public class TopologyMetricsCacheDeadlockTest {

    public static void main(final String[] args) throws Exception {
        // Set up the component graph
        final long sessionTtlMs = 1; // very short TTL to force expiry/renewal
        final MetricsSessionManager sessionManager = new MetricsSessionManager(sessionTtlMs);

        // Enable rebalancing mode so that session renewals change the shard,
        // which triggers the invalidation listener
        sessionManager.setRebalancingMode(true);

        final StreamsMetricsConnector connector = new StreamsMetricsConnector(sessionManager);

        final long cacheTtlMs = 1; // very short TTL to force cache misses
        final TopologyMetricsCache cache = new TopologyMetricsCache(connector, cacheTtlMs);

        // Register the invalidation listener so that session changes call back into the cache
        sessionManager.registerListener(cache.createInvalidationListener());

        // Mark transport invalid so that getSnapshot's fetch path takes the
        // slow (exclusive-lock) refresh path
        connector.markTransportInvalid();

        // Thread 1: getSnapshot() — acquires cache lock, then transportLock
        final Thread snapshotThread = new Thread(() -> {
            for (int i = 0; i < 20; i++) {
                connector.markTransportInvalid();
                cache.getSnapshot("test-topology");
            }
        }, "snapshot-thread");

        // Thread 2: performMaintenance() — acquires transportLock, then (via listener) cache lock
        final Thread maintenanceThread = new Thread(() -> {
            for (int i = 0; i < 20; i++) {
                sessionManager.setRebalancingMode(true);
                connector.performMaintenance();
            }
        }, "maintenance-thread");

        snapshotThread.start();
        maintenanceThread.start();

        snapshotThread.join();
        maintenanceThread.join();
    }
}

